  SELECT id INTO v_bloque_id FROM bloques WHERE pilar_id = v_pilar_id AND nombre = 'MANIPULACIÓN DE MATERIALES Y ERGONOMÍA';

  INSERT INTO preguntas (id, bloque_id, key, numero, texto, mandatorio, peso, guia, requerimiento, puntaje_criterio, como_verificar)
  VALUES (
    gen_random_uuid(),
    v_bloque_id,
    '7_1_35_118',
    '4.1',
    'Ejecución segura de manipulación manual de materiales',
    false,
    1,
    'Proposito: garantizar que se aplican las técnicas de elevación y la configuración del puesto de trabajo adecuadas para evitar lesiones.',
    'R4.1.1 - Prácticas de elevación seguras implementadas durante la manipulación manual de materiales según lo definido. 
R4.1.2 - Estación de trabajo evaluada con controles/soluciones ergonómicas adecuadas identificadas.  Resolución 886/15 (estudio de ergonomia)
R4.1.3 - Plan de acción para cerrar las brechas en los controles ergonómicos de los puestos de trabajo.',
    '{"0":"R4.1.2 no se cumple","1":"R4.1.2 se cumple pero R4.1.3 no está en proceso o > 1 lesión relacionada con la manipulación manual de materiales","3":"R4.1.2, R4.1.3 se cumplen y no más de 1 lesión relacionada con la manipulación manual de materiales","5":"Todos los requisitos cumplen y 0 lesiones relacionadas con la manipulación manual de materiales"}'::jsonb,
    '1. Comprobar si los operadores aplican prácticas de elevación seguras durante la manipulación manual de materiales tal como se define en el protocolo. 
2. Observar los puestos de trabajo para evaluar si cumplen los controles ergonómicos definidos en la evaluación de riesgos de instalaciones/zonas - con adecuaciones ergonomicas realizadas.
3. Compruebe la herramienta de notificación de incidentes - compruebe si hay lesiones relacionadas con la manipulación manual de materiales. Compruebe si hay un plan de acción para cerrar las brechas.'
  );

  INSERT INTO preguntas (id, bloque_id, key, numero, texto, mandatorio, peso, guia, requerimiento, puntaje_criterio, como_verificar)
  VALUES (
    gen_random_uuid(),
    v_bloque_id,
    '7_1_35_119',
    '4.2',
    'Gestión de equipos de elevación mecánica, racks y estantes',
    false,
    1,
    'Proposito: garantizar que los equipos de elevación se inspeccionan y mantienen adecuadamente. Esto también garantiza que las estanterías de la instalación se inspeccionen, mantengan y utilicen adecuadamente.',
    'R4.2.1 - Inspecciones anuales documentadas de todos los equipos de elevación. (racks, estanterias)
R4.2.2 - Registro de acciones para completar cualquier problema que se encuentre en la inspección anual. 
R4.2.3 Inspecciones trimestrales documentadas para todas las estanterías y racks. 
R4.2.4 Inspecciones anuales documentadas para todas las estanterías y racks. 
R4.2.5 Registro de acciones para completar cualquier problema como se encuentra en las inspecciones trimestrales y anuales. 
R4.2.6 - Asegurar estandar de racks y estanterias (OPL, etiquetado con capacidad máxima, condiciones optimas, analisis de bastidores chocados, cobertores en los extremos de bastidores y transversales, red de contención para racks).
R4.2.7 - Operadores conscientes de los puntos críticos y qué hacer si un punto crítico no está en condiciones de funcionar. 
R4.2.8 - Si se detectan problemas, el equipo de elevación se retira del servicio y se corrige antes del próximo uso.',
    '{"0":"R4.2.1, R4.2.3, R4.2.4, R4.2.6 o R4.8 no cumplió","1":"R4.2.1, R4.2.3, R4.2.4, R4.2.6 y R4.2.8 pero R4.2.2 o R4.2.5 no actualizados","3":"Todos los requisitos excepto 4.2.7 cumplieron","5":"Todos los requisitos cumplieron"}'::jsonb,
    '1. Revisar los documentos de inspección anuales tanto para el equipo de elevación como para los racks y estantes; comprobar si la inspección ha sido completada por una parte cualificada según los requisitos legales locales. 
2. Examinar los documentos de inspección trimestrales para comprobar si el equipo está cualificado para hacerlo 
3. Comprobar si hay resultados en las inspecciones anuales, revisar el registro de medidas para cerrar las lagunas y comprobar si está actualizado. 
4. Hablar con los operadores: comprobar que puedan explicar el proceso de inspección previo al uso. 
5. Comprobar si los operadores conocen los puntos críticos y qué hacer si no funcionan. 
6. Comprobar si el aparato de elevación presenta deficiencias en los puntos críticos y si está en servicio.'
  );

  INSERT INTO preguntas (id, bloque_id, key, numero, texto, mandatorio, peso, guia, requerimiento, puntaje_criterio, como_verificar)
  VALUES (
    gen_random_uuid(),
    v_bloque_id,
    '7_1_35_120',
    '4.3',
    'Ejecución segura de equipos de elevación mecánica',
    true,
    1,
    'Propósito: Garantizar que el equipo de elevación se utilice correctamente siguiendo un procedimiento escrito disponible para los empleados. El cumplimiento del protocolo debe mantenerse a través de nuestras rutinas de Observación del Trabajo Diario (OWD) y sesiones de entrenamiento. 

El término "equipo de elevación" se refiere de manera general a cualquier equipo que pueda utilizarse para levantar y bajar cargas (ejemplos: gato hidráulico, plataformas elevadoras y grúas). En esta solicitud, los elementos en la pregunta 3.5 no serán evaluados.',
    'R4.3.1 - Procedimientos de equipos de elevación escritos, completos y disponibles para los empleados.

R4.3.2 - Operadores ejecutan equipos de elevación siguiendo el procedimiento.

R4.3.3 - Coaching completado para garantizar que los operadores ejecuten equipos de elevación de acuerdo con el procedimiento.

R4.3.4 - La gerencia realiza Observaciones del Trabajo Diario (OWD) a los procedimientos de equipos de elevación.',
    '{"0":"No se cumple R4.3.1.","1":"Se cumple R4.3.1, PERO no se cumple R4.3.2 (ha ocurrido un Incidente Crítico Potencial o Incidente Crítico Real relacionado con R4.3.2).","3":"Todos los requisitos cumplidos, PERO los resultados de coaching/OWD no muestran una tendencia positiva.","5":"Todos los requisitos cumplidos Y tendencia positiva en los resultados de coaching/Observaciones del Trabajo Diario (OWD)."}'::jsonb,
    'Verificar si los procedimientos de equipos de elevación están escritos, completos y disponibles para los empleados.

1.-Observar a los operadores utilizando equipos de elevación: verificar si los operadores siguen de manera segura los procedimientos de equipos de elevación.

2.-Revisar la Gestión de Incidentes: ¿ha habido un Incidente Crítico Potencial o Incidente Crítico Real relacionado con el incumplimiento de las reglas de operación segura?

3.-Verificar el registro de entrenamiento del centro: verificar si hay entrenamiento sobre la ejecución de equipos de elevación (tanto positivo como correctivo).

4.-Revisar las Observaciones del Trabajo Diario (OWDs) del centro: verificar si se están realizando diagnósticos sobre los procedimientos de equipos de elevación.'
  );
