  INSERT INTO preguntas (id, bloque_id, key, numero, texto, mandatorio, peso, guia, requerimiento, puntaje_criterio, como_verificar)
  VALUES (
    gen_random_uuid(),
    v_bloque_id,
    '7_1_36_124',
    '5.4',
    'Almacenamiento y transporte seguro de tubos de gas comprimido',
    false,
    1,
    'Documente procedimiento sobre sustancias peligrosas y el almacenamiento y transporte de bombonas de gas comprimido.',
    'R5.4.1 - Cilindros de gas comprimido almacenados correctamente.
R5.4.2 - Cilindros de gas comprimido mantenidos en buen estado. 
R5.4.3 - Procedimientos de manipulación de cilindros de gas comprimido definidos y almacenados correctamente.
R5.4.4 - Transporte de cilindros alineados con el protocolo. 
R5.4.5 - Señalización y zonas de peligro identificadas dentro del almacen.
R5.4.6 - Entrenamiento completo para asegurar que los operadores lleven a cabo la manipulación de cilindros de gas comprimido de conformidad con el procedimiento. 
R5.4.7 - La dirección lleva a cabo procedimientos de OWD a la manipulacion de cilindros de gas comprimido.',
    '{"0":"R5.4.1, R5.4.2, R5.4.3 o R5.4.5 no se cumplen","1":"R5.4.1, R5.4.2, R5.4.3 y R5.4.5 cumplieron pero R5.4.4 no se cumplieron (un potencial SIF o SIF actual relacionado con R5.4.4)","3":"Todos los requisitos se cumplieron pero los resultados de coaching/OWD no mostraron tendencia de mejora","5":"Se cumplieron todos los requisitos y se mejoró la tendencia en los resultados de coaching/OWD"}'::jsonb,
    '1. Observar las zonas de almacenamiento: observar si los cilindros de gas comprimido están almacenados según lo definido en el protocolo. 
2. Observe si están en buenas condiciones y adecuadamente protegidos. 
3. Compruebe si los procedimientos de manipulación de los cilindros de gas comprimido están definidos/fijados. 
4. Comprobar si el transporte de cilindros se gestiona según lo definido en el protocolo. 
5. Obsérvese si hay señalización y se comunican los peligros de la zona. 
6. Compruebe la Gestión de Incidentes: ¿ha habido un Potencial SIF o SIF actual relacionado con reglas de funcionamiento seguras que no se siguen? 
7. Compruebe el registro de entrenamiento de la instalación - compruebe si hay entrenamiento en el manejo de cilindros de gas comprimido (positivo y correctivo). 
8. Comprobar las OWD de la instalación - comprobar si se están realizando diagnósticos en procedimientos de manipulación de cilindros de gas comprimido.'
  );

  INSERT INTO preguntas (id, bloque_id, key, numero, texto, mandatorio, peso, guia, requerimiento, puntaje_criterio, como_verificar)
  VALUES (
    gen_random_uuid(),
    v_bloque_id,
    '7_1_36_125',
    '5.5',
    'Almacenamiento de sustancias peligrosas',
    false,
    1,
    'Documente procedimiento sobre sustancias peligrosas y el almacenamiento de sustancias peligrosas.',
    'R5.5.1 - Sustancias peligrosas debidamente almacenadas en contenedor secundario. (bateas de contención, según la capacidad)
R5.5.2 - Productos incompatibles almacenados por separado. 
R5.5.3 - Ventilación adecuada en el área de almacenamiento. 
R5.5.4 - Área correctamente etiquetada y controlada con matriz de compatibilidad. 
R5.5.5 - Residuos eliminados correctamente de acuerdo con la reglamentación.',
    '{"0":"R5.5.2, R5.5.3, R5.5.4 y R5.5.5 no cumplieron","1":"R5.5.5.2, R5.5.3, R5.5.5 y R5.5 - Se incumplieron >1 violación de R5.5.1","3":"R5.5.2, R5.5.3, R5.5.4 y R5.5.5 cumplieron pero 1 violación de R5.5.1","5":"Todos los requisitos cumplieron"}'::jsonb,
    '1. Observación de las zonas de almacenamiento de productos químicos: Comprobar si los productos químicos se almacenan en una batea secundaria para contener derrames. 
2. Observar si los productos incompatibles se almacenan por separado. 
3. Comprobar si existe una ventilación adecuada en la zona de almacenamiento. 
4. Obsérvese si la zona está debidamente etiquetada y controlada, incluida una matriz de compatibilidad. 
5. Comprobar si los residuos se eliminan correctamente en conformidad con las directrices reglamentarias.'
  );

  INSERT INTO preguntas (id, bloque_id, key, numero, texto, mandatorio, peso, guia, requerimiento, puntaje_criterio, como_verificar)
